import React from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip, Divider } from '@mui/material';
import response from './response.json';

interface Blocker {
  name: string;
  details: string;
}

interface StandupSummaryData {
  yesterdayCompletions: number;
  todaysPlan: string[];
  blockers: Blocker[];
}

export default function Widget() {
  const standupData = response.data as StandupSummaryData;
  const { yesterdayCompletions, todaysPlan, blockers } = standupData;

  return (
    <Card sx={{ width: 'fit-content', minWidth: 320, maxWidth: 450, bgcolor: '#2C2C2E', color: '#FFFFFF' }} elevation={2}>
      <CardContent sx={{ p: 2 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107' }}>
              Standup Summary
            </Typography>
            <Typography variant="body2" sx={{ color: '#B0BEC5', mt: 1 }}>
              Yesterday's Completions: {yesterdayCompletions}
            </Typography>
          </Box>

          <Divider sx={{ bgcolor: '#FFC107' }} />

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 1 }}>
              Today's Plan
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {todaysPlan.map((task, index) => (
                <Chip
                  key={index}
                  label={task}
                  sx={{ fontSize: '11px', bgcolor: '#424242', color: '#FFFFFF' }}
                />
              ))}
            </Stack>
          </Box>

          <Divider sx={{ bgcolor: '#FFC107' }} />

          <Box>
            <Typography variant="body2" sx={{ color: '#FFC107', mb: 1 }}>
              Blockers
            </Typography>
            <Stack spacing={1}>
              {blockers.map((blocker, index) => (
                <Box key={index}>
                  <Typography variant="body2" sx={{ fontWeight: 500 }}>
                    {blocker.name}
                  </Typography>
                  <Typography variant="caption" color="text.secondary">
                    {blocker.details}
                  </Typography>
                </Box>
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
